"use client";

import {
  autoUpdate,
  computePosition,
  flip,
  offset as floatingOffset,
  shift,
  type Placement,
  type Strategy,
} from "@floating-ui/dom";
import { useEffect, useState, type CSSProperties, type RefObject } from "react";

type UseFloatingPositionOptions<
  TReference extends HTMLElement,
  TFloating extends HTMLElement,
> = {
  floatingRef: RefObject<TFloating | null>;
  matchReferenceWidth?: boolean;
  offset?: number;
  open: boolean;
  padding?: number;
  placement?: Placement;
  referenceRef: RefObject<TReference | null>;
  strategy?: Strategy;
};

function hiddenStyle(strategy: Strategy): CSSProperties {
  return {
    left: 0,
    opacity: 0,
    pointerEvents: "none",
    position: strategy,
    top: 0,
  };
}

export function useFloatingPosition<
  TReference extends HTMLElement = HTMLElement,
  TFloating extends HTMLElement = HTMLElement,
>({
  floatingRef,
  matchReferenceWidth = false,
  offset = 8,
  open,
  padding = 12,
  placement = "bottom-start",
  referenceRef,
  strategy = "fixed",
}: UseFloatingPositionOptions<TReference, TFloating>) {
  const [style, setStyle] = useState<CSSProperties>(() =>
    hiddenStyle(strategy),
  );

  useEffect(() => {
    if (!open) {
      setStyle(hiddenStyle(strategy));
      return;
    }

    const reference = referenceRef.current;
    const floating = floatingRef.current;

    if (!reference || !floating) {
      return;
    }

    let active = true;

    const updatePosition = () => {
      const referenceWidth = matchReferenceWidth
        ? reference.getBoundingClientRect().width
        : undefined;

      void computePosition(reference, floating, {
        middleware: [
          floatingOffset(offset),
          flip({ padding }),
          shift({ padding }),
        ],
        placement,
        strategy,
      }).then(({ x, y }) => {
        if (!active) {
          return;
        }

        setStyle({
          left: x,
          opacity: 1,
          position: strategy,
          top: y,
          width: referenceWidth,
        });
      });
    };

    const cleanup = autoUpdate(reference, floating, updatePosition, {
      elementResize: typeof ResizeObserver !== "undefined",
      layoutShift: typeof IntersectionObserver !== "undefined",
    });

    return () => {
      active = false;
      cleanup();
    };
  }, [
    floatingRef,
    matchReferenceWidth,
    offset,
    open,
    padding,
    placement,
    referenceRef,
    strategy,
  ]);

  return style;
}

const focusableSelector = [
  "a[href]",
  "button:not([disabled])",
  "textarea:not([disabled])",
  "input:not([disabled])",
  "select:not([disabled])",
  "[tabindex]:not([tabindex='-1'])",
].join(",");

export function getFocusableElements(container: HTMLElement) {
  return Array.from(container.querySelectorAll<HTMLElement>(focusableSelector))
    .filter((element) => !element.hasAttribute("disabled"))
    .filter((element) => element.getAttribute("aria-hidden") !== "true");
}

export function focusInitialElement(container: HTMLElement) {
  const firstFocusable = getFocusableElements(container)[0] ?? container;
  firstFocusable.focus();
}

export function trapFocus(container: HTMLElement, event: KeyboardEvent) {
  if (event.key !== "Tab") {
    return;
  }

  const focusableElements = getFocusableElements(container);

  if (focusableElements.length === 0) {
    event.preventDefault();
    container.focus();
    return;
  }

  const firstElement = focusableElements[0];
  const lastElement = focusableElements[focusableElements.length - 1];
  const activeElement = document.activeElement;

  if (event.shiftKey && activeElement === firstElement) {
    event.preventDefault();
    lastElement.focus();
    return;
  }

  if (!event.shiftKey && activeElement === lastElement) {
    event.preventDefault();
    firstElement.focus();
  }
}

import {
  Children,
  cloneElement,
  forwardRef,
  isValidElement,
  type CSSProperties,
  type HTMLAttributes,
  type ReactElement,
  type ReactNode,
  type Ref,
} from "react";
import clsx, { type ClassValue } from "clsx";

// create the swirski tone system
export type SwirskiTone =
  | "muted"
  | "subtle"
  | "inverted"
  | "blue"
  | "yellow"
  | "red"
  | "white"
  | "black";

// create the swirski size system
export type SwirskiSize = "xs" | "sm" | "md" | "lg" | "xl" | "display";

// create the swirski variant system
export type SwirskiVariant = "solid" | "outline" | "soft" | "ghost" | "plain";

export type SwirskiSystemProps<
  Variant extends string = SwirskiVariant,
  Size extends string = SwirskiSize,
  Tone extends string = SwirskiTone,
> = {
  className?: string;
  variant?: Variant;
  size?: Size;
  tone?: Tone;
};

export type SwirskiPolymorphicProps = {
  asChild?: boolean;
  children?: ReactNode;
};
// combines class names
export function cn(...inputs: ClassValue[]) {
  return clsx(...inputs);
}

export const focusVisibleStyles =
  "focus-visible:outline focus-visible:outline-[length:var(--sw-border-width)] focus-visible:outline-offset-2 focus-visible:outline-[var(--sw-color-focus)]";

export const disabledInteractiveStyles =
  "disabled:cursor-not-allowed disabled:opacity-60 disabled:hover:translate-x-0 disabled:hover:translate-y-0 disabled:active:translate-x-0 disabled:active:translate-y-0 disabled:active:scale-100";

// apply swirski data attributes to component
export function swirskiAttrs(
  component: string,
  options: {
    size?: string;
    tone?: string;
    variant?: string;
  } = {},
) {
  return {
    "data-swirski-component": component,
    "data-swirski-size": options.size,
    "data-swirski-tone": options.tone,
    "data-swirski-variant": options.variant,
  };
}
// compose the refs so that refs and passed refs will work together
export function composeRefs<T>(...refs: Array<Ref<T> | undefined>) {
  return (node: T | null) => {
    refs.forEach((ref) => {
      if (!ref) {
        return;
      }

      if (typeof ref === "function") {
        ref(node);
        return;
      }

      ref.current = node;
    });
  };
}

function isEventHandler(key: string, value: unknown) {
  return /^on[A-Z]/.test(key) && typeof value === "function";
}

function mergeSlotProps(
  slotProps: HTMLAttributes<HTMLElement>,
  childProps: HTMLAttributes<HTMLElement>,
) {
  const mergedProps = { ...slotProps, ...childProps };

  for (const key of Object.keys(childProps)) {
    const slotValue = slotProps[key as keyof HTMLAttributes<HTMLElement>];
    const childValue = childProps[key as keyof HTMLAttributes<HTMLElement>];

    if (isEventHandler(key, slotValue) && isEventHandler(key, childValue)) {
      mergedProps[key as keyof HTMLAttributes<HTMLElement>] = ((
        event: unknown,
      ) => {
        (childValue as (event: unknown) => void)(event);
        (slotValue as (event: unknown) => void)(event);
      }) as never;
    }
  }

  return {
    ...mergedProps,
    "aria-describedby": mergeAriaIds(
      childProps["aria-describedby"],
      slotProps["aria-describedby"],
    ),
    className: cn(slotProps.className, childProps.className),
    style: {
      ...(slotProps.style as CSSProperties | undefined),
      ...(childProps.style as CSSProperties | undefined),
    },
  };
}

function mergeAriaIds(...values: Array<string | undefined>) {
  const ids = values.flatMap((value) => value?.split(/\s+/) ?? []);
  const uniqueIds = Array.from(new Set(ids.filter(Boolean)));

  return uniqueIds.length ? uniqueIds.join(" ") : undefined;
}

export type SlotProps = HTMLAttributes<HTMLElement> & {
  children?: ReactNode;
};

export const Slot = forwardRef<HTMLElement, SlotProps>(
  ({ children, ...props }, forwardedRef) => {
    const child = Children.only(children);

    if (!isValidElement(child)) {
      throw new Error("Swirski asChild expects a single valid React element.");
    }

    const childElement = child as ReactElement<HTMLAttributes<HTMLElement>>;
    const childRef = (childElement.props as { ref?: Ref<HTMLElement> }).ref;

    return cloneElement(childElement, {
      ...mergeSlotProps(props, childElement.props),
      ref: composeRefs(forwardedRef, childRef),
    } as HTMLAttributes<HTMLElement> & { ref: Ref<HTMLElement> });
  },
);

Slot.displayName = "Slot";

"use client";

import { useEffect, useRef, type RefObject } from "react";
import { focusInitialElement, trapFocus as trapFocusWithin } from "./focus";

let bodyScrollLockCount = 0;
let originalBodyOverflow = "";

function lockBodyScroll() {
  if (bodyScrollLockCount === 0) {
    originalBodyOverflow = document.body.style.overflow;
    document.body.style.overflow = "hidden";
  }

  bodyScrollLockCount += 1;

  return () => {
    bodyScrollLockCount = Math.max(0, bodyScrollLockCount - 1);

    if (bodyScrollLockCount === 0) {
      document.body.style.overflow = originalBodyOverflow;
      originalBodyOverflow = "";
    }
  };
}

export type UseModalOverlayOptions = {
  autoFocus?: boolean;
  contentRef: RefObject<HTMLElement | null>;
  lockScroll?: boolean;
  onEscape: () => void;
  open: boolean;
  restoreFocus?: boolean;
  trapFocus?: boolean;
};

export function useModalOverlay({
  autoFocus = true,
  contentRef,
  lockScroll = true,
  onEscape,
  open,
  restoreFocus = true,
  trapFocus = true,
}: UseModalOverlayOptions) {
  const onEscapeRef = useRef(onEscape);

  useEffect(() => {
    onEscapeRef.current = onEscape;
  }, [onEscape]);

  useEffect(() => {
    if (!open) {
      return;
    }

    const previouslyFocusedElement =
      document.activeElement as HTMLElement | null;
    const releaseScrollLock = lockScroll ? lockBodyScroll() : undefined;
    const animationFrame = autoFocus
      ? window.requestAnimationFrame(() => {
          if (contentRef.current) {
            focusInitialElement(contentRef.current);
          }
        })
      : undefined;

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        onEscapeRef.current();
        return;
      }

      if (trapFocus && contentRef.current) {
        trapFocusWithin(contentRef.current, event);
      }
    };

    window.addEventListener("keydown", handleKeyDown);

    return () => {
      if (animationFrame !== undefined) {
        window.cancelAnimationFrame(animationFrame);
      }

      releaseScrollLock?.();
      window.removeEventListener("keydown", handleKeyDown);

      if (
        restoreFocus &&
        previouslyFocusedElement &&
        document.contains(previouslyFocusedElement)
      ) {
        previouslyFocusedElement.focus();
      }
    };
  }, [autoFocus, contentRef, lockScroll, open, restoreFocus, trapFocus]);
}

"use client";

import { CSSProperties, HTMLAttributes, ReactNode, createContext, useContext } from "react";
import clsx from "clsx";

export type SwirskiColorScheme = "light" | "dark";

export type SwirskiThemeTokens = {
  colorInk: string;
  colorPaper: string;
  colorSurface: string;
  colorMuted: string;
  colorBlue: string;
  colorYellow: string;
  colorRed: string;
  colorWhite: string;
  colorBlack: string;
  colorShadow: string;
  colorFocus: string;
  borderWidth: string;
  shadowSm: string;
  shadowMd: string;
  shadowLg: string;
  fontBody: string;
  fontHeading: string;
  fontDisplay: string;
};

export type SwirskiTheme = Partial<SwirskiThemeTokens> & {
  cssVariables?: Record<string, string>;
};

export type SwirskiProviderProps = {
  children: ReactNode;
  colorScheme?: SwirskiColorScheme;
  theme?: SwirskiTheme;
} & HTMLAttributes<HTMLDivElement>;

const defaultTokens: SwirskiThemeTokens = {
  colorInk: "#0B0B0C",
  colorPaper: "#F5F5F3",
  colorSurface: "#FFFFFF",
  colorMuted: "rgba(11, 11, 12, 0.68)",
  colorBlue: "#0057FF",
  colorYellow: "#FFD400",
  colorRed: "#FF3131",
  colorWhite: "#FFFFFF",
  colorBlack: "#0B0B0C",
  colorShadow: "#0B0B0C",
  colorFocus: "#0057FF",
  borderWidth: "4px",
  shadowSm: "3px 3px 0 var(--sw-color-shadow)",
  shadowMd: "6px 6px 0 var(--sw-color-shadow)",
  shadowLg: "10px 10px 0 var(--sw-color-shadow)",
  fontBody: "var(--font-inter, system-ui, sans-serif)",
  fontHeading: "var(--font-anton, Impact, sans-serif)",
  fontDisplay: "var(--font-bangers, Impact, fantasy)",
};

const darkTokens: Partial<SwirskiThemeTokens> = {
  colorInk: "#F7F7F2",
  colorPaper: "#121212",
  colorSurface: "#1D1D1F",
  colorMuted: "rgba(247, 247, 242, 0.68)",
  colorWhite: "#1D1D1F",
  colorBlack: "#F7F7F2",
  colorShadow: "#FFD400",
  colorFocus: "#FFD400",
};

const tokenVariables: Record<keyof SwirskiThemeTokens, string> = {
  colorInk: "--sw-color-ink",
  colorPaper: "--sw-color-paper",
  colorSurface: "--sw-color-surface",
  colorMuted: "--sw-color-muted",
  colorBlue: "--sw-color-blue",
  colorYellow: "--sw-color-yellow",
  colorRed: "--sw-color-red",
  colorWhite: "--sw-color-white",
  colorBlack: "--sw-color-black",
  colorShadow: "--sw-color-shadow",
  colorFocus: "--sw-color-focus",
  borderWidth: "--sw-border-width",
  shadowSm: "--sw-shadow-sm",
  shadowMd: "--sw-shadow-md",
  shadowLg: "--sw-shadow-lg",
  fontBody: "--sw-font-body",
  fontHeading: "--sw-font-heading",
  fontDisplay: "--sw-font-display",
};

const SwirskiThemeContext = createContext<SwirskiThemeTokens>(defaultTokens);

export const swirskiDefaultTheme = defaultTokens;
export const swirskiDarkTheme = { ...defaultTokens, ...darkTokens };

function resolveTheme(
  colorScheme: SwirskiColorScheme,
  theme?: SwirskiTheme,
): SwirskiThemeTokens {
  const schemeTokens =
    colorScheme === "dark" ? swirskiDarkTheme : swirskiDefaultTheme;

  return {
    ...schemeTokens,
    ...theme,
  };
}

function themeToStyle(theme: SwirskiThemeTokens, extra?: SwirskiTheme) {
  const style: Record<string, string> = {};

  Object.entries(tokenVariables).forEach(([tokenName, variableName]) => {
    style[variableName] = theme[tokenName as keyof SwirskiThemeTokens];
  });

  Object.entries(extra?.cssVariables ?? {}).forEach(([name, value]) => {
    style[name] = value;
  });

  return style as CSSProperties;
}

export function createSwirskiTheme(theme: SwirskiTheme) {
  return theme;
}

export function SwirskiProvider({
  children,
  className,
  colorScheme = "light",
  style,
  theme,
  ...props
}: SwirskiProviderProps) {
  const resolvedTheme = resolveTheme(colorScheme, theme);

  return (
    <SwirskiThemeContext.Provider value={resolvedTheme}>
      <div
        className={clsx(
          "swirski-provider min-h-full bg-[var(--sw-color-paper)] text-[var(--sw-color-ink)]",
          className,
        )}
        data-swirski-color-scheme={colorScheme}
        style={{ ...themeToStyle(resolvedTheme, theme), ...style }}
        {...props}
      >
        {children}
      </div>
    </SwirskiThemeContext.Provider>
  );
}

export function useSwirskiTheme() {
  return useContext(SwirskiThemeContext);
}

export {
  SwirskiProvider,
  createSwirskiTheme,
  swirskiDarkTheme,
  swirskiDefaultTheme,
  useSwirskiTheme,
} from "./SwirskiProvider";
export type {
  SwirskiColorScheme,
  SwirskiProviderProps,
  SwirskiTheme,
  SwirskiThemeTokens,
} from "./SwirskiProvider";

@import "tailwindcss";

@import "@fontsource/anton";
@import "@fontsource/bangers";

@source "./src/**/*.{ts,tsx}";
@source "./dist/**/*.{js,mjs,cjs}";

:root,
[data-swirski-color-scheme="light"] {
  --sw-color-ink: #0b0b0c;
  --sw-color-paper: #f5f5f3;
  --sw-color-surface: #ffffff;
  --sw-color-muted: rgba(11, 11, 12, 0.68);
  --sw-color-blue: #0057ff;
  --sw-color-yellow: #ffd400;
  --sw-color-red: #ff3131;
  --sw-color-white: #ffffff;
  --sw-color-black: #0b0b0c;
  --sw-color-shadow: #0b0b0c;
  --sw-color-focus: #0057ff;
  --sw-border-width: 4px;
  --sw-shadow-sm: 3px 3px 0 var(--sw-color-shadow);
  --sw-shadow-md: 6px 6px 0 var(--sw-color-shadow);
  --sw-shadow-lg: 10px 10px 0 var(--sw-color-shadow);
  --sw-font-body: var(--font-inter, system-ui, sans-serif);
  --sw-font-heading: var(--font-anton, "Anton", sans-serif);
  --sw-font-display: var(--font-bangers, "Bangers", cursive);
}

[data-swirski-color-scheme="dark"] {
  --sw-color-ink: #f7f7f2;
  --sw-color-paper: #121212;
  --sw-color-surface: #1d1d1f;
  --sw-color-muted: rgba(247, 247, 242, 0.68);
  --sw-color-white: #1d1d1f;
  --sw-color-black: #f7f7f2;
  --sw-color-shadow: #ffd400;
  --sw-color-focus: #ffd400;
}

.swirski-provider {
  min-height: 100%;
  background: var(--sw-color-paper);
  color: var(--sw-color-ink);
  font-family: var(--sw-font-body);
}

@theme inline {
  --font-anton: "Anton", sans-serif;
  --font-bangers: "Bangers", cursive;
}

@keyframes swirski-pixel-bounce {
  0%,
  100% {
    transform: translateY(0);
  }

  50% {
    transform: translateY(-55%);
  }
}

@keyframes swirski-pixel-bars {
  0%,
  100% {
    transform: scaleY(0.45);
  }

  50% {
    transform: scaleY(1);
  }
}

@keyframes swirski-pixel-flicker {
  0%,
  100% {
    opacity: 1;
    transform: translate(0, 0);
  }

  50% {
    opacity: 0.45;
    transform: translate(1px, -1px);
  }
}

@keyframes swirski-pixel-scan {
  0%,
  100% {
    transform: translateX(-100%);
  }

  50% {
    transform: translateX(100%);
  }
}

@media (prefers-reduced-motion: reduce) {
  [data-swirski-component="loader"] *,
  [data-swirski-component="loader"] {
    animation-duration: 1ms !important;
    animation-iteration-count: 1 !important;
  }
}
